const MODEL = "deepseek-v4-flash";

export interface AiCallOptions {
  messages: { role: "system" | "user" | "assistant"; content: string }[];
  temperature?: number;  // default 0.3
  timeout?: number;      // default 5000
}

export async function callDeepSeek<T = unknown>(options: AiCallOptions): Promise<T> {
  // AbortController 超时 5000ms
  // fetch POST /v1/chat/completions
  // Authorization: Bearer process.env.AI_API_KEY
  // body: { model, messages, temperature, response_format: { type: "json_object" } }
  // 解析 choices[0].message.content → JSON.parse → T
  // AbortError → throw "DeepSeek API timeout"
  // 非 ok → throw "DeepSeek API error: {status}"
  // finally: clearTimeout
}
```

### 2. `lib/ai/triage.ts` — 故障分诊规则强制
```typescript
export interface TriageResult {
  category: "hardware" | "software" | "user_error";
  severity: "high" | "medium" | "low";
  needRepair: boolean;
  reason: string;
  selfHelp: string | null;
}

export function enforceTriageRules(result: TriageResult): TriageResult {
  // severity=high → needRepair 强制 true
  // needRepair=true → selfHelp = null
  // needRepair=false 且无 selfHelp → 兜底文案 "请尝试重启设备，如问题持续请联系IT支持。"
}
```

### 3. `lib/ai/confirmation-token.ts` — Token 确认机制
```typescript
