  fn: () => Promise<T>,
  fallbackMessage: string,
): Promise<{ ok: true; data: T } | { ok: false; fallback: string }> {
  // try/catch, console.error('[AI Fallback]', error)
}
```

### 5. `app/api/ai/recommend/route.ts` — 设备推荐
POST，EMPLOYEE/MANAGER:
- 接收 `{ requirement: string }`
- 查 active models（含 IN_STOCK 库存数 via _count instances）
- System Prompt（中文）: 角色=设备推荐助手, 输入=需求描述+型号列表JSON, 输出={recommendations:[{modelId,score,reason}], topPick}
- 约束: 忽略 DISCONTINUED, stock=0 标注"暂无库存", score 0-100
- User Prompt: 用户需求 + modelListJson
- 调用 callDeepSeek, 用 withAiFallback 降级
- 降级文案: "推荐服务暂时不可用，请稍后重试或浏览全部可用型号自行选择。"

### 6. `app/api/ai/triage/route.ts` — 故障分诊
POST，EMPLOYEE/MANAGER:
- 接收 `{ description: string }`
- System Prompt（中文）: 角色=IT故障诊断助手, 分类{hardware,software,user_error}, 严重程度{high,medium,low}, 输出={category,severity,needRepair,reason,selfHelp}
- hardware→needRepair=true, software→优先自助, user_error→no repair
- 调用 callDeepSeek, 然后 enforceTriageRules 后处理
- 降级文案: "故障诊断暂时不可用，你的报修工单已提交，IT 管理员将尽快处理。"

### 7. `app/api/ai/chat/route.ts` — AI 对话助手 (重点)
POST，任何认证用户:
- 接收 `{ message: string, history: {role:"user"|"assistant", content:string}[] }`
- 查询用户上下文: 持有的资产列表(incl model) + 待处理工单列表
- System Prompt（完整中文）:
  ```
  角色: IT助手
  原则: 简洁友好中文, 涉及创建工单/申领需二次确认, 询问价格/供应商回复"抱歉该信息不在你的权限范围内"
  输入: {history, message, userContext:{assets:[{id,modelName,brandName,category,status,warrantyExpiry}], pendingTickets:[{id,type,status,createdAt}]}}
  意图分类: query_asset, query_warranty, query_ticket, guide_repair(需确认), guide_apply(需确认), fallback
  输出: {intent, reply, needConfirmation:bool, pendingAction:{type:"create_repair"|"create_apply", description, params}|null}
  ```
- 如果 needConfirmation=true: 生成 confirmationToken 返回给前端
- 降级文案: "AI 助手暂时不可用，你可以通过「我的资产」查看资产信息，或通过「申领设备」/「报修」提交申请。"

