const DEEPSEEK_BASE = process.env.AI_BASE_URL ?? "https://api.deepseek.com/v1";
const MODEL = "deepseek-v4-flash";

export interface AiCallOptions {
  messages: { role: "system" | "user" | "assistant"; content: string }[];
  temperature?: number;
  timeout?: number;
}

export async function callDeepSeek<T = unknown>(
  options: AiCallOptions,
): Promise<T> {
  const timeout = options.timeout ?? 5000;
  const temperature = options.temperature ?? 0.3;

  const apiKey = process.env.AI_API_KEY;
  if (!apiKey) {
    throw new Error("AI_API_KEY is not configured");
  }

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeout);

  try {
    const response = await fetch(`${DEEPSEEK_BASE}/chat/completions`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${apiKey}`,
      },
      body: JSON.stringify({
        model: MODEL,
        messages: options.messages,
        temperature,
        response_format: { type: "json_object" },
      }),
      signal: controller.signal,
    });

    if (!response.ok) {
      throw new Error(`DeepSeek API error: ${response.status}`);
    }

    const data = (await response.json()) as {
      choices: { message: { content: string } }[];
    };
    const content = data.choices[0].message.content;
    return JSON.parse(content) as T;
  } catch (error) {
    if (error instanceof DOMException && error.name === "AbortError") {
      throw new Error("DeepSeek API timeout");
    }
    throw error;
  } finally {
    clearTimeout(timer);
  }
}

export interface TriageResult {
  category: "hardware" | "software" | "user_error";
  severity: "high" | "medium" | "low";
  needRepair: boolean;
  reason: string;
  selfHelp: string | null;
}

export function enforceTriageRules(result: TriageResult): TriageResult {
  const enforced: TriageResult = { ...result };

  // severity=high → needRepair 强制 true
  if (enforced.severity === "high") {
    enforced.needRepair = true;
  }

  // needRepair=true → selfHelp = null
  if (enforced.needRepair) {
    enforced.selfHelp = null;
  }

  // needRepair=false 且无 selfHelp → 兜底文案
  if (!enforced.needRepair && !enforced.selfHelp) {
    enforced.selfHelp =
      "请尝试重启设备，如问题持续请联系IT支持。";
  }

  return enforced;
}

import { SignJWT, jwtVerify } from "jose";

const USED_TOKENS = new Set<string>();

function getSecretKey(): Uint8Array {
  const secret =
    (process.env.AUTH_SECRET ??
      "it-asset-dev-secret-change-in-production") + ":confirmation";
  return new TextEncoder().encode(secret);
}

export interface ConfirmationPayload {
  userId: string;
  action: string;
  params: Record<string, unknown>;
}

export async function generateConfirmationToken(
  payload: ConfirmationPayload,
): Promise<string> {
  const key = getSecretKey();

  const token = await new SignJWT({ ...payload })
    .setProtectedHeader({ alg: "HS256" })
    .setExpirationTime("300s")
    .sign(key);

  return token;
}

export async function verifyConfirmationToken(
  token: string,
  userId: string,
): Promise<ConfirmationPayload | null> {
  if (USED_TOKENS.has(token)) {
    return null;
  }

  try {
    const key = getSecretKey();
    const { payload } = await jwtVerify(token, key);

    if (payload.userId !== userId) {
      return null;
    }

    USED_TOKENS.add(token);

    return {
      userId: payload.userId as string,
      action: payload.action as string,
      params: payload.params as Record<string, unknown>,
    };
  } catch {
    return null;
  }
}

export async function withAiFallback<T>(
  fn: () => Promise<T>,
  fallbackMessage: string,
): Promise<{ ok: true; data: T } | { ok: false; fallback: string }> {
  try {
    const data = await fn();
    return { ok: true, data };
  } catch (error) {
    console.error("[AI Fallback]", error);
    return { ok: false, fallback: fallbackMessage };
  }
}

